1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const DEDUCTIBLE = 100;
57	const CAP_MULTIPLIER = 2;
58	
59	interface ItemPricing {
60	  basePremium: number;
61	  insuranceValue: number;
62	}
63	
64	const ITEM_PRICING: Record<string, ItemPricing> = {
65	  sword: { basePremium: 100, insuranceValue: 1000 },
66	  amulet: { basePremium: 60, insuranceValue: 600 },
67	  staff: { basePremium: 80, insuranceValue: 800 },
68	  potion: { basePremium: 40, insuranceValue: 400 },
69	  rune: { basePremium: 25, insuranceValue: 250 },
70	  moonstone: { basePremium: 25, insuranceValue: 250 },
71	};
72	
73	const pricingFor = (type: string): ItemPricing =>
74	  ITEM_PRICING[type] ?? { basePremium: 0, insuranceValue: 0 };
75	
76	export const isKnownItemType = (type: string): boolean => type in ITEM_PRICING;
77	
78	const CURSED_SURCHARGE_RATE = 0.5;
79	const HIGH_ENCHANTMENT_THRESHOLD = 5;
80	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
81	const FIRST_INSURANCE_RATE = 0.1;
82	const LOYALTY_THRESHOLD_YEARS = 2;
83	const LOYALTY_DISCOUNT_RATE = 0.2;
84	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
85	
86	const isCursed = (item: Item): boolean => item.cursed === true;
87	const isHighlyEnchanted = (item: Item): boolean =>
88	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
89	
90	const surchargeRate = (item: Item): number =>
91	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
92	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
93	
94	const itemBaseValue = (item: Item): number => pricingFor(item.type).basePremium;
95	
96	const itemSurcharge = (item: Item): number =>
97	  itemBaseValue(item) * surchargeRate(item);
98	
99	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
100	const BLOCK_SIZE = 3;
101	const BLOCK_PREMIUM = 60;
102	
103	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
104	
105	const sumBy = <T>(values: T[], measure: (value: T) => number): number =>
106	  values.reduce((sum, value) => sum + measure(value), 0);
107	
108	const groupByType = (items: Item[]): Item[][] => {
109	  const byType = new Map<string, Item[]>();
110	  for (const item of items) {
111	    const group = byType.get(item.type) ?? [];
112	    group.push(item);
113	    byType.set(item.type, group);
114	  }
115	  return [...byType.values()];
116	};
117	
118	const groupPremium = (group: Item[]): number =>
119	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBy(group, itemBaseValue);
120	
121	const partition = <T>(values: T[], predicate: (value: T) => boolean): [T[], T[]] => {
122	  const matches: T[] = [];
123	  const rest: T[] = [];
124	  for (const value of values) {
125	    (predicate(value) ? matches : rest).push(value);
126	  }
127	  return [matches, rest];
128	};
129	
130	const policyBasePremium = (items: Item[]): number => {
131	  const [components, mainItems] = partition(items, isComponent);
132	  return sumBy(groupByType(components), groupPremium) + sumBy(mainItems, itemBaseValue);
133	};
134	
135	const totalSurcharges = (items: Item[]): number => sumBy(items, itemSurcharge);
136	
137	const loyaltyRate = (customer: Customer): number =>
138	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0;
139	
140	const followUpRate = (isFollowUp: boolean): number =>
141	  isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
142	
143	const netPolicyRate = (customer: Customer, isFollowUp: boolean): number =>
144	  FIRST_INSURANCE_RATE - loyaltyRate(customer) - followUpRate(isFollowUp);
145	
146	const quotePremium = (customer: Customer, items: Item[], isFollowUp: boolean): number => {
147	  const base = policyBasePremium(items);
148	  const surcharges = totalSurcharges(items);
149	  const policyAdjustment = base * netPolicyRate(customer, isFollowUp);
150	  return Math.ceil(base + surcharges + policyAdjustment + PROCESSING_FEE);
151	};
152	
153	interface Policy {
154	  items: Item[];
155	  remainingCap: number;
156	}
157	
158	const insuranceSum = (items: Item[]): number =>
159	  sumBy(items, (item) => pricingFor(item.type).insuranceValue);
160	
161	const newPolicy = (items: Item[]): Policy => ({
162	  items,
163	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
164	});
165	
166	const HIGH_ENCHANTMENT_DAMAGE_THRESHOLD = 8;
167	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
168	
169	const triggersHalfReimbursement = (item: Item | undefined): boolean =>
170	  item !== undefined && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_DAMAGE_THRESHOLD;
171	
172	const reimbursementAmount = (item: Item | undefined, damageAmount: number): number =>
173	  triggersHalfReimbursement(item)
174	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
175	    : damageAmount;
176	
177	const insuredItemFor = (policy: Policy, itemType: string): Item | undefined =>
178	  policy.items.find((item) => item.type === itemType);
179	
180	const damagePayout = (policy: Policy, damage: Damage): number => {
181	  const insuredItem = insuredItemFor(policy, damage.itemType);
182	  return reimbursementAmount(insuredItem, damage.amount) - DEDUCTIBLE;
183	};
184	
185	const countByKey = <T>(values: T[], keyOf: (value: T) => string): Map<string, number> => {
186	  const counts = new Map<string, number>();
187	  for (const value of values) {
188	    const key = keyOf(value);
189	    counts.set(key, (counts.get(key) ?? 0) + 1);
190	  }
191	  return counts;
192	};
193	
194	const validateDamagesCoveredByPolicy = (policy: Policy, damages: Damage[]): void => {
195	  const insuredCounts = countByKey(policy.items, (item) => item.type);
196	  const damageCounts = countByKey(damages, (damage) => damage.itemType);
197	  for (const [type, damagedCount] of damageCounts) {
198	    const insuredCount = insuredCounts.get(type) ?? 0;
199	    if (insuredCount === 0) {
200	      throw new Error(`claim references item type '${type}' which is not in the policy`);
201	    }
202	    if (damagedCount > insuredCount) {
203	      throw new Error(`damages for type '${type}' exceed insured count (${damagedCount} > ${insuredCount})`);
204	    }
205	  }
206	};
207	
208	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
209	  validateDamagesCoveredByPolicy(policy, incident.damages);
210	  const totalDamagePayout = sumBy(incident.damages, (damage) => damagePayout(policy, damage));
211	  const payout = Math.min(Math.floor(totalDamagePayout), policy.remainingCap);
212	  return { payout, remainingCap: policy.remainingCap - payout };
213	};
214	
215	const handleQuote = (
216	  customer: Customer,
217	  step: QuoteStep,
218	  index: number,
219	  policies: Map<number, Policy>,
220	): QuoteResult => {
221	  const isFollowUp = policies.size > 0;
222	  policies.set(index, newPolicy(step.items));
223	  return { premium: quotePremium(customer, step.items, isFollowUp) };
224	};
225	
226	const handleClaim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
227	  const policy = policies.get(step.policy)!;
228	  const result = processClaim(policy, step.incident);
229	  policies.set(step.policy, { ...policy, remainingCap: result.remainingCap });
230	  return result;
231	};
232	
233	export const runScenario = (scenario: Scenario): ScenarioResult => {
234	  const policies = new Map<number, Policy>();
235	  const results = scenario.steps.map((step, index): StepResult =>
236	    step.op === "quote"
237	      ? handleQuote(scenario.customer, step, index, policies)
238	      : handleClaim(step, policies),
239	  );
240	  return { results };
241	};
