1	import { runScenario, isKnownItemType, type Item, type Scenario, type Step } from "./claim-office.js";
2	
3	const readStdin = async (): Promise<string> => {
4	  const chunks: Buffer[] = [];
5	  for await (const chunk of process.stdin) {
6	    chunks.push(chunk as Buffer);
7	  }
8	  return Buffer.concat(chunks).toString("utf8");
9	};
10	
11	const quotedItems = (steps: Step[]): Item[] =>
12	  steps.flatMap((step) => (step.op === "quote" ? step.items : []));
13	
14	const claimDamages = (steps: Step[]) =>
15	  steps.flatMap((step) => (step.op === "claim" ? step.incident.damages : []));
16	
17	const validateScenario = (scenario: Scenario): void => {
18	  const unknown = quotedItems(scenario.steps).find((item) => !isKnownItemType(item.type));
19	  if (unknown !== undefined) {
20	    throw new Error(`unknown item type: '${unknown.type}'`);
21	  }
22	  const negative = claimDamages(scenario.steps).find((damage) => damage.amount < 0);
23	  if (negative !== undefined) {
24	    throw new Error(`damage amount must be non-negative, got ${negative.amount}`);
25	  }
26	};
27	
28	const main = async (): Promise<void> => {
29	  const input = await readStdin();
30	  const scenario = JSON.parse(input) as Scenario;
31	  validateScenario(scenario);
32	  const result = runScenario(scenario);
33	  process.stdout.write(JSON.stringify(result));
34	};
35	
36	main().catch((error: unknown) => {
37	  const message = error instanceof Error ? error.message : String(error);
38	  process.stderr.write(`${message}\n`);
39	  process.exit(1);
40	});
